import React from 'react';
import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { useAuth } from './context/AuthContext';

import Login from './pages/Login';
import Register from './pages/Register';
import DoctorDashboard from './pages/DoctorDashboard';
import PatientDashboard from './pages/PatientDashboard';
import Patients from './pages/Patients';
import RecordForm from './pages/RecordForm';
import RecordDetail from './pages/RecordDetail';
import Appointments from './pages/Appointments';
import AppointmentForm from './pages/AppointmentForm';
import Profile from './pages/Profile';
import Vitals from './pages/Vitals';
import Timeline from './pages/Timeline';
import AuditLogs from './pages/AuditLogs';
import Layout from './components/Layout';

const PrivateRoute = ({ children, roles }) => {
  const { user, loading } = useAuth();
  if (loading) return <div className="d-flex justify-content-center mt-5"><div className="spinner-border" /></div>;
  if (!user) return <Navigate to="/login" />;
  if (roles && !roles.includes(user.role)) return <Navigate to="/dashboard" />;
  return children;
};

export default function App() {
  const { user } = useAuth();

  return (
    <BrowserRouter>
      <Routes>
        <Route path="/login" element={<Login />} />
        <Route path="/register" element={<Register />} />

        <Route path="/" element={<PrivateRoute><Layout /></PrivateRoute>}>
          <Route index element={<Navigate to="/dashboard" />} />
          <Route
            path="dashboard"
            element={user?.role === 'patient' ? <PatientDashboard /> : <DoctorDashboard />}
          />
          <Route path="patients" element={<PrivateRoute roles={['admin', 'doctor']}><Patients /></PrivateRoute>} />
          <Route path="records/new" element={<PrivateRoute roles={['admin', 'doctor']}><RecordForm /></PrivateRoute>} />
          <Route path="records/:id/edit" element={<PrivateRoute roles={['admin', 'doctor']}><RecordForm /></PrivateRoute>} />
          <Route path="records/:id" element={<RecordDetail />} />
          <Route path="appointments" element={<Appointments />} />
          <Route path="appointments/new" element={<AppointmentForm />} />
          <Route path="vitals" element={<Vitals />} />
          <Route path="timeline" element={<Timeline />} />
          <Route path="timeline/:patientId" element={<PrivateRoute roles={['admin', 'doctor']}><Timeline /></PrivateRoute>} />
          <Route path="audit" element={<PrivateRoute roles={['admin']}><AuditLogs /></PrivateRoute>} />
          <Route path="profile" element={<Profile />} />
        </Route>

        <Route path="*" element={<Navigate to="/dashboard" />} />
      </Routes>
    </BrowserRouter>
  );
}
